import functions_framework
import hmac
import hashlib
import json
import os
from flask import jsonify

WEBHOOK_SECRET = os.environ.get('WEBHOOK_SECRET', 'your-secret-key-change-in-production')

def verify_webhook_signature(payload, signature_header):
    """Verify the webhook signature using HMAC SHA256"""
    if not signature_header:
        return False
    
    expected_signature = hmac.new(
        WEBHOOK_SECRET.encode('utf-8'),
        payload.encode('utf-8'),
        hashlib.sha256
    ).hexdigest()
    
    return hmac.compare_digest(expected_signature, signature_header)

def process_payment_event(event_type, event_data):
    """Process different types of payment events"""
    handlers = {
        'payment.succeeded': handle_payment_succeeded,
        'payment.failed': handle_payment_failed,
        'payment.refunded': handle_payment_refunded,
        'subscription.created': handle_subscription_created,
        'subscription.cancelled': handle_subscription_cancelled
    }
    
    handler = handlers.get(event_type)
    if handler:
        return handler(event_data)
    else:
        return {'status': 'unknown_event', 'event_type': event_type}

def handle_payment_succeeded(data):
    """Handle successful payment"""
    payment_id = data.get('payment_id')
    amount = data.get('amount')
    currency = data.get('currency')
    customer_id = data.get('customer_id')
    
    print(f"Payment succeeded: {payment_id}, Amount: {amount} {currency}, Customer: {customer_id}")
    
    return {'status': 'processed', 'payment_id': payment_id}

def handle_payment_failed(data):
    """Handle failed payment"""
    payment_id = data.get('payment_id')
    reason = data.get('reason')
    customer_id = data.get('customer_id')
    
    print(f"Payment failed: {payment_id}, Reason: {reason}, Customer: {customer_id}")
    
    return {'status': 'processed', 'payment_id': payment_id}

def handle_payment_refunded(data):
    """Handle payment refund"""
    payment_id = data.get('payment_id')
    refund_amount = data.get('refund_amount')
    customer_id = data.get('customer_id')
    
    print(f"Payment refunded: {payment_id}, Amount: {refund_amount}, Customer: {customer_id}")
    
    return {'status': 'processed', 'payment_id': payment_id}

def handle_subscription_created(data):
    """Handle subscription creation"""
    subscription_id = data.get('subscription_id')
    customer_id = data.get('customer_id')
    plan = data.get('plan')
    
    print(f"Subscription created: {subscription_id}, Customer: {customer_id}, Plan: {plan}")
    
    return {'status': 'processed', 'subscription_id': subscription_id}

def handle_subscription_cancelled(data):
    """Handle subscription cancellation"""
    subscription_id = data.get('subscription_id')
    customer_id = data.get('customer_id')
    
    print(f"Subscription cancelled: {subscription_id}, Customer: {customer_id}")
    
    return {'status': 'processed', 'subscription_id': subscription_id}

@functions_framework.http
def payment_webhook(request):
    """HTTP Cloud Function for payment webhook processing
    
    Args:
        request (flask.Request): The request object
    Returns:
        The response text, or any set of values that can be turned into a
        Response object using `make_response`
    """
    
    if request.method != 'POST':
        return jsonify({'error': 'Method not allowed'}), 405
    
    signature_header = request.headers.get('X-Webhook-Signature')
    
    try:
        request_data = request.get_data(as_text=True)
        
        if not verify_webhook_signature(request_data, signature_header):
            print("Webhook signature verification failed")
            return jsonify({'error': 'Invalid signature'}), 401
        
        payload = json.loads(request_data)
        
        event_type = payload.get('event_type')
        event_data = payload.get('data', {})
        event_id = payload.get('event_id')
        
        if not event_type or not event_id:
            return jsonify({'error': 'Missing required fields'}), 400
        
        print(f"Processing webhook event: {event_id}, Type: {event_type}")
        
        result = process_payment_event(event_type, event_data)
        
        response = {
            'received': True,
            'event_id': event_id,
            'result': result
        }
        
        return jsonify(response), 200
        
    except json.JSONDecodeError:
        print("Invalid JSON payload")
        return jsonify({'error': 'Invalid JSON'}), 400
    except Exception as e:
        print(f"Error processing webhook: {str(e)}")
        return jsonify({'error': 'Internal server error'}), 500